


-- Extra data for remaining tables

SELECT i, 'Material_' || i, round((random()*100 + 10)::numeric, 2), 'kg', (random()*1000)::int
FROM generate_series(1, 500) AS i;

SELECT i, 'Employee_' || i, 'Family_' || i, DATE '2020-01-01' + (i % 1000), 'Worker'
FROM generate_series(1, 500) AS i;

SELECT i, 'Morning', 8, DATE '2024-01-01' + (i % 365), 'Generated shift'
FROM generate_series(1, 500) AS i;

SELECT i, DATE '2024-01-01' + (i % 365), round((random()*5000 + 100)::numeric, 2), 'Pending', 'Truck', i
FROM generate_series(1, 500) AS i;

SELECT i, 'Factory_' || (i % 10), (random()*1000 + 100)::int, DATE '2024-01-01' + (i % 365), 'Active', i
FROM generate_series(1, 500) AS i;

SELECT i, 'Department_' || i, 'Location_' || (i % 20), round((random()*100000 + 10000)::numeric, 2), 'Manager_' || i, i, i
FROM generate_series(1, 500) AS i;

SELECT i, i
FROM generate_series(1, 500) AS i;

SELECT i, i
FROM generate_series(1, 500) AS i;

SELECT i, i
FROM generate_series(1, 500) AS i;

-- Add more rows to reach 20,000 records in Product
SELECT 
    i,
    'Generated Product ' || i,
    round((random() * 300 + 20)::numeric, 2),
    round((random() * 10 + 0.5)::numeric, 2),
    DATE '2024-01-01' + (i % 365)
FROM generate_series(501, 20000) AS i;

-- Add more rows to reach 20,000 records in RawMaterial
SELECT 
    i,
    'Generated Material ' || i,
    round((random() * 100 + 5)::numeric, 2),
    'kg',
    (random() * 1000)::int
FROM generate_series(501, 20000) AS i;